INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '518e2e40-a269-4be8-8345-70c16357991f',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi's TanStack Query Integration — Cache, Invalidate, and Prefetch Ethereum Data$escape$,
  $escape$wagmi v2 is built on TanStack Query, which means every hook like `useBalance`, `useReadContract`, and `useBlockNumber` is a query under the hood. You get automatic caching, background refetching, and deduplication for free — no custom state management needed.

Each wagmi hook accepts `query` config to control caching behavior. Set `staleTime: Infinity` for static contract data like token decimals, or `refetchInterval: 4_000` to poll every block. You can also call `queryClient.invalidateQueries({ queryKey })` after a write to immediately refresh dependent reads.

wagmi exports `useQueryClient` and query key factories via `hashFn` and `readContractQueryOptions`, letting you construct precise query keys for targeted invalidation. After a `useWriteContract` mutation confirms, invalidate just the affected balance or allowance query rather than nuking the entire cache.

Connectors (MetaMask, WalletConnect, Coinbase) are first-class in this model too — `useAccount` and `useChainId` sync via wagmi's internal store, while on-chain reads flow through TanStack Query, giving you a clean separation between wallet state and contract data.$escape$,
  $escape$import { useReadContract, useWriteContract, useQueryClient } from 'wagmi'
import { readContractQueryOptions } from 'wagmi/query'
import { erc20Abi } from 'viem'

const queryClient = useQueryClient()
const { writeContractAsync } = useWriteContract()

const { data: balance } = useReadContract({
  address: '0xTokenAddress',
  abi: erc20Abi,
  functionName: 'balanceOf',
  args: ['0xUserAddress'],
  query: { staleTime: 10_000 },
})

async function approveAndInvalidate() {
  await writeContractAsync({ address: '0xTokenAddress', abi: erc20Abi, functionName: 'approve', args: ['0xSpender', 1000n] })
  const opts = readContractQueryOptions(config, { address: '0xTokenAddress', abi: erc20Abi, functionName: 'balanceOf', args: ['0xUserAddress'] })
  queryClient.invalidateQueries({ queryKey: opts.queryKey })
}$escape$,
