INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e2a279ad-a7eb-4b9e-af02-54a11850b4d9',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi + The Graph — Query Indexed Blockchain History Instead of Scanning Events$escape$,
  $escape$wagmi's `useWatchContractEvent` catches live events, but it can't reach historical data. That's The Graph's job. A subgraph indexes your contract's emitted events into a PostgreSQL-backed GraphQL API — you define the schema in a manifest, deploy it, and query history instantly.

wagmi v2 is built on TanStack Query, so pairing it with `graphql-request` is idiomatic: use `useQuery` directly with The Graph endpoint as the fetcher. Pull `address` from `useAccount()` and pass it as a variable — no custom hooks required.

Hosted Service (`api.thegraph.com`) is free and centralized — fine for dev/staging but deprecated for new subgraphs. The decentralized network (`gateway.thegraph.com`) requires GRT and an API key, but gives you SLA-backed indexing with redundancy. For production wagmi apps, migrate to the decentralized endpoint and gate your key server-side or via an env-prefixed Next.js route handler to avoid leaking it client-side.

Subgraphs eliminate the need for `getLogs` pagination or a custom indexer for most read-heavy use cases.$escape$,
  $escape$import { useAccount } from 'wagmi'
import { useQuery } from '@tanstack/react-query'
import { request, gql } from 'graphql-request'

const SUBGRAPH = 'https://api.thegraph.com/subgraphs/name/uniswap/uniswap-v3'

const SWAPS = gql`
  query GetSwaps($user: String!) {
    swaps(where: { origin: $user }, first: 10, orderBy: timestamp, orderDirection: desc) {
      amountUSD
      timestamp
      pool { token0 { symbol } token1 { symbol } }
    }
  }
`

export function useUserSwaps() {
  const { address } = useAccount()
  return useQuery({
    queryKey: ['swaps', address],
    queryFn: () => request(SUBGRAPH, SWAPS, { user: address?.toLowerCase() }),
    enabled: !!address,
  })
}$escape$,
  $escape$typescript$escape$,
