INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ab2ef3b8-2df9-4b41-8eb9-d3607d4539d6',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi — Reading On-chain Data with useReadContract, getLogs, and Multicall$escape$,
  $escape$wagmi's `useReadContract` maps directly to `eth_call` under the hood — it reads contract state without sending a transaction. For a single slot, pass `address`, `abi`, `functionName`, and `args`. Results are typed via viem's ABI inference, so you get autocomplete on return values.

For event history, use `useWatchContractEvent` for live streaming or viem's `getLogs` via `usePublicClient` for historical queries. Pass `fromBlock`, `toBlock`, and an `event` ABI entry to filter precisely — no topic encoding needed.

Batch multiple reads with `useReadContracts`, which batches calls into a single JSON-RPC `eth_call` using multicall3 by default. Each contract in the `contracts` array returns `{ data, error, status }` independently, so partial failures don't break the batch.

Avoid `useContractRead` (deprecated). Prefer `useReadContract` for single reads and `useReadContracts` for batches. Set `watch: true` on any hook to revalidate on new blocks without manual polling.$escape$,
  $escape$import { useReadContracts, usePublicClient } from 'wagmi'
import { erc20Abi, parseAbiItem } from 'viem'

const { data } = useReadContracts({
  contracts: [
    { address: '0xA0b...', abi: erc20Abi, functionName: 'balanceOf', args: ['0xUser...'] },
    { address: '0xA0b...', abi: erc20Abi, functionName: 'totalSupply' },
  ],
})

const client = usePublicClient()
const logs = await client.getLogs({
  address: '0xA0b...',
  event: parseAbiItem('event Transfer(address indexed from, address indexed to, uint256 value)'),
  fromBlock: 20_000_000n,
  toBlock: 'latest',
})$escape$,
