INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '33cb5f72-049c-48be-acb4-5776eedb1304',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi Transaction Writing — Simulate, Send, and Monitor in One Flow$escape$,
  $escape$wagmi v2 splits transaction writing into three distinct hooks that mirror the actual on-chain lifecycle. Use `useSimulateContract` first — it dry-runs the call via `eth_call` and returns a typed `request` object, catching reverts before spending gas. Feed that `request` directly into `useWriteContract` to get a `writeContract` function and the resulting `hash`. Critically, `useSimulateContract` also handles gas estimation internally; override with `gas` only when you need a ceiling. Nonce management is handled by the connected wallet by default, but you can pass `nonce` explicitly for account abstraction or batching scenarios. Once you have a `hash`, hand it to `useWaitForTransactionReceipt` to poll for confirmation — it exposes `status` (`'pending' | 'success' | 'error'`), `confirmations`, and the full `TransactionReceipt`. Chain the enabled flag on `useWaitForTransactionReceipt` so it only activates post-submission. This three-hook pattern gives you granular error surfaces: simulation errors ≠ send errors ≠ receipt errors.$escape$,
  $escape$import { useSimulateContract, useWriteContract, useWaitForTransactionReceipt } from 'wagmi'
import { parseEther } from 'viem'

const { data: simData } = useSimulateContract({
  address: '0xContractAddress',
  abi,
  functionName: 'deposit',
  value: parseEther('0.1'),
})

const { writeContract, data: hash } = useWriteContract()

const { status, data: receipt } = useWaitForTransactionReceipt({
  hash,
  confirmations: 2,
})

// simData.request is typed — pass directly, no manual gas/nonce needed
return <button onClick={() => writeContract(simData!.request)}>Deposit</button>$escape$,
  $escape$typescript$escape$,
