INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd985f1d2-4e89-41f6-8d82-8d19d80348af',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi ENS — Name Resolution, Avatars, and Reverse Lookup in One Hook$escape$,
  $escape$wagmi ships first-class ENS support via `useEnsAddress`, `useEnsName`, `useEnsAvatar`, and `useEnsText` — no ethers.js manual calls needed. Forward resolution maps a name like `vitalik.eth` to an address via `useEnsAddress({ name: normalize('vitalik.eth') })`. Always wrap inputs with `normalize` from `viem/ens` to prevent ENS normalization errors at runtime. Reverse resolution flips it: pass a raw address to `useEnsName({ address })` to retrieve the primary name set by the user. For avatars, `useEnsAvatar({ name })` resolves the `avatar` text record and handles IPFS, Arweave, and HTTP URIs transparently. Arbitrary records — Twitter handle, email, URL — are read with `useEnsText({ name, key: 'com.twitter' })`. All four hooks accept a `chainId` prop so you can target ENS on mainnet even when the user's wallet is on a different chain. Combine `useEnsName` + `useEnsAvatar` on the connected account to build a fully resolved identity header with two lines of hook usage.$escape$,
  $escape$import { useEnsAddress, useEnsName, useEnsAvatar, useEnsText } from 'wagmi'
import { normalize } from 'viem/ens'
import { useAccount } from 'wagmi'

function UserIdentity() {
  const { address } = useAccount()

  const { data: ensName } = useEnsName({ address, chainId: 1 })
  const { data: avatar } = useEnsAvatar({ name: ensName ?? undefined, chainId: 1 })
  const { data: twitter } = useEnsText({ name: normalize('vitalik.eth'), key: 'com.twitter', chainId: 1 })
  const { data: resolved } = useEnsAddress({ name: normalize('vitalik.eth'), chainId: 1 })

  return <div>{avatar && <img src={avatar} />} {ensName ?? address}</div>
}$escape$,
  $escape$typescript$escape$,
