INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ad028cc-b5e6-4aff-ad05-d0aae9064a56',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi — Testing with Forked Mainnet and Mocked Contracts$escape$,
  $escape$wagmi's `WagmiProvider` expects a real or simulated chain. For integration tests, the sharpest approach is pairing wagmi with `viem`'s `createTestClient` over a Hardhat or Foundry forked mainnet — giving your hooks access to live state without touching real funds.

Wrap your test tree with a `WagmiProvider` configured against a `hardhat` or `anvil` transport pointed at your local fork (`http://127.0.0.1:8545`). Use `createConfig` with `chains: [hardhat]` and `transports: { [hardhat.id]: http() }`. Now `useReadContract`, `useWriteContract`, and `useWaitForTransactionReceipt` all resolve against forked state.

For unit tests where you want deterministic responses without a running node, swap the transport for `mock()` from `@wagmi/core/test`. Feed it a `requests` handler array that intercepts specific RPC calls — perfect for simulating reverts, specific balances, or ERC-20 allowance responses. Combine `mock()` transport with `renderHook` from Testing Library to test hook behavior in isolation, asserting on `data`, `error`, and `isPending` transitions without any network dependency.$escape$,
  $escape$import { createConfig, http } from 'wagmi'
import { hardhat } from 'wagmi/chains'
import { mock } from '@wagmi/core/test'
import { renderHook, waitFor } from '@testing-library/react'
import { useReadContract } from 'wagmi'
import { wrapper } from './test-utils' // WagmiProvider wrapper

const mockConfig = createConfig({
  chains: [hardhat],
  transports: {
    [hardhat.id]: mock({
      requests: [
        { method: 'eth_call', result: '0x000000000000000000000000000000000000000000000000002386f26fc10000' },
      ],
    }),
  },
})

test('useReadContract returns mocked balance', async () => {
  const { result } = renderHook(
    () => useReadContract({ address: '0xTokenAddress', abi: erc20Abi, functionName: 'balanceOf', args: ['0xUserAddress'] }),
    { wrapper: wrapper(mockConfig) }
  )
  await waitFor(() => expect(result.current.data).toBeDefined())
})$escape$,
  $escape$typescript$escape$,
